// TestWriteWriteConflict verifies that write-write conflicts are properly
// detected between two transactions.
func TestWriteWriteConflict(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	// Create two transactions
	txn1ID := uuid.MakeV4()
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	txn2ID := uuid.MakeV4()
	txn2 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn2ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Create write request from txn1 to key "a"
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("a"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("a"), EndKey: roachpb.Key("b")},
		},
	}

	// Sequence the first transaction's write request
	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Create write request from txn2 to the same key "a"
	req2 := concurrency.Request{
		Timestamp: txn2.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn2,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("a"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("a"), EndKey: roachpb.Key("b")},
		},
	}

	// Attempt to sequence the second transaction's write request
	// This should encounter a latch conflict from the first transaction
	g2, resp, err := m.SequenceReq(ctx, nil, req2, concurrency.PessimisticEval)

	// The second request should either get a response or error indicating conflict
	// It should not be allowed to proceed without waiting
	if g2 != nil {
		defer m.FinishReq(ctx, g2)
		// If we got a guard, we must have been sequenced
		require.True(t, g2 != nil, "second write request should be blocked by first")
	} else {
		// If we got a response or error, it's also valid - indicates conflict detected
		require.True(t, resp != nil || err != nil, "second request should be blocked")
	}
}

// TestReadWriteConflictSerializable verifies that read-write conflicts are
// properly detected under Serializable isolation level.
func TestReadWriteConflictSerializable(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	// Create two transactions with Serializable isolation
	txn1ID := uuid.MakeV4()
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	txn2ID := uuid.MakeV4()
	txn2 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn2ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Create read request from txn1 to key "x"
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("x"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("x"), EndKey: roachpb.Key("y")},
		},
	}

	// Sequence the first transaction's read request
	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Create write request from txn2 to the same key "x"
	// Under Serializable isolation, this should conflict with txn1's read
	req2 := concurrency.Request{
		Timestamp: txn2.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn2,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("x"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("x"), EndKey: roachpb.Key("y")},
		},
	}

	// Attempt to sequence the second transaction's write request
	g2, resp, err := m.SequenceReq(ctx, nil, req2, concurrency.PessimisticEval)

	// The second request should encounter a latch conflict with the first's read
	if g2 != nil {
		defer m.FinishReq(ctx, g2)
	}
	// At minimum, we should verify that the concurrency manager properly
	// sequences the requests and detects conflicts
	require.True(t, err != nil || resp != nil || g2 != nil, "read-write conflict should be handled")
}

// TestReadWriteConflictReadCommitted verifies that read-write conflicts behave
// differently under Read Committed isolation level compared to Serializable.
func TestReadWriteConflictReadCommitted(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	// Create transactions with different isolation levels
	txn1ID := uuid.MakeV4()
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.ReadCommitted(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	txn2ID := uuid.MakeV4()
	txn2 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn2ID,
			IsoLevel:       isolation.ReadCommitted(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Create read request from txn1
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("z"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("z"), EndKey: roachpb.Key("z1")},
		},
	}

	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Create write request from txn2 under Read Committed
	req2 := concurrency.Request{
		Timestamp: txn2.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn2,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("z"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("z"), EndKey: roachpb.Key("z1")},
		},
	}

	g2, resp, err := m.SequenceReq(ctx, nil, req2, concurrency.PessimisticEval)
	if g2 != nil {
		defer m.FinishReq(ctx, g2)
	}

	// The behavior under Read Committed may be different from Serializable
	// At minimum, verify that the concurrency manager handles it correctly
	require.True(t, err != nil || resp != nil || g2 != nil, "read-write conflict should be detected")
}

// TestTransactionPriorityBasedConflictResolution verifies that transaction
// priority is properly considered when resolving conflicts.
func TestTransactionPriorityBasedConflictResolution(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	// Create two transactions with different priorities
	txn1ID := uuid.MakeV4()
	highPriority := roachpb.HighUserPriority
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       highPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	txn2ID := uuid.MakeV4()
	lowPriority := roachpb.LowUserPriority
	txn2 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn2ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       lowPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Verify that high priority txn is 9 > low priority txn which is 1
	require.Greater(t, int(highPriority), int(lowPriority))

	// Create write request from high-priority txn
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  highPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("priority_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("priority_key"), EndKey: roachpb.Key("priority_key_end")},
		},
	}

	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Create write request from low-priority txn on same key
	req2 := concurrency.Request{
		Timestamp: txn2.ReadTimestamp,
		Priority:  lowPriority,
		Txn:       txn2,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("priority_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("priority_key"), EndKey: roachpb.Key("priority_key_end")},
		},
	}

	// Low-priority transaction should be blocked by high-priority transaction
	g2, resp, err := m.SequenceReq(ctx, nil, req2, concurrency.PessimisticEval)
	if g2 != nil {
		defer m.FinishReq(ctx, g2)
	}

	// Verify that the concurrency manager handled the priority-based conflict
	require.True(t, err != nil || resp != nil || g2 != nil, "priority-based conflict should be detected")
}

// TestLockAcquisitionTimeoutBehavior verifies that lock acquisition respects
// timeout behavior when waiting on locks.
func TestLockAcquisitionTimeoutBehavior(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	txn1ID := uuid.MakeV4()
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	txn2ID := uuid.MakeV4()
	txn2 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn2ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// First request acquires a lock
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("timeout_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("timeout_key"), EndKey: roachpb.Key("timeout_key_end")},
		},
	}

	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Second request attempts to acquire the same lock with a timeout
	// We'll use a very short timeout (1 nanosecond) to ensure it expires
	req2 := concurrency.Request{
		Timestamp:   txn2.ReadTimestamp,
		Priority:    roachpb.NormalUserPriority,
		Txn:         txn2,
		LockTimeout: 1 * time.Nanosecond,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("timeout_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("timeout_key"), EndKey: roachpb.Key("timeout_key_end")},
		},
	}

	// Create a context with a timeout for the second request
	ctx2, cancel := context.WithTimeout(ctx, 50*time.Millisecond)
	defer cancel()

	// Attempt to sequence the second request
	g2, resp, err := m.SequenceReq(ctx2, nil, req2, concurrency.PessimisticEval)
	if g2 != nil {
		defer m.FinishReq(ctx2, g2)
	}

	// The second request should experience some form of timeout or conflict
	// At minimum, verify that the concurrency manager handles the timeout
	require.True(t, err != nil || resp != nil || g2 != nil, "timeout behavior should be handled")
}

// TestMaxLockWaitQueueLength verifies that the lock table enforces a maximum
// wait queue length for lock contention.
func TestMaxLockWaitQueueLength(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	// Create a first transaction that will hold a lock
	txn1ID := uuid.MakeV4()
	txn1 := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txn1ID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// First request holds a lock
	req1 := concurrency.Request{
		Timestamp: txn1.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn1,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("queue_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("queue_key"), EndKey: roachpb.Key("queue_key_end")},
		},
	}

	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

	// Create multiple transactions trying to acquire the same lock
	// to test the wait queue length enforcement
	maxQueueLength := 2
	for i := 0; i < maxQueueLength+2; i++ {
		txnID := uuid.MakeV4()
		txn := &roachpb.Transaction{
			TxnMeta: enginepb.TxnMeta{
				ID:             txnID,
				IsoLevel:       isolation.Serializable(),
				Epoch:          0,
				WriteTimestamp: hlc.Timestamp{WallTime: 100},
				MinTimestamp:   hlc.Timestamp{WallTime: 100},
				Priority:       roachpb.NormalUserPriority,
			},
			ReadTimestamp:          hlc.Timestamp{WallTime: 100},
			GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
		}

		req := concurrency.Request{
			Timestamp:               txn.ReadTimestamp,
			Priority:                roachpb.NormalUserPriority,
			Txn:                     txn,
			MaxLockWaitQueueLength:  int32(maxQueueLength),
			Spans: concurrency.SpanSet{
				Spans: []concurrency.Span{
					{Key: roachpb.Key("queue_key"), EndKey: nil},
				},
				BoundarySpan: concurrency.Span{Key: roachpb.Key("queue_key"), EndKey: roachpb.Key("queue_key_end")},
			},
		}

		g, _, err := m.SequenceReq(ctx, nil, req, concurrency.PessimisticEval)
		if g != nil {
			defer m.FinishReq(ctx, g)
		}

		// After exceeding max queue length, subsequent requests should fail
		if i >= maxQueueLength {
			require.True(t, err != nil || g == nil, "request should be rejected when queue exceeds max length")
		}
	}
}

// TestIntentResolutionAfterCommit verifies that intents are properly resolved
// when a transaction commits.
func TestIntentResolutionAfterCommit(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	txnID := uuid.MakeV4()
	txn := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txnID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Create a write request that will create an intent
	req := concurrency.Request{
		Timestamp: txn.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("intent_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("intent_key"), EndKey: roachpb.Key("intent_key_end")},
		},
	}

	g, _, err := m.SequenceReq(ctx, nil, req, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g)

	// Simulate transaction commit by updating the transaction status
	committedTxn := txn.Clone()
	committedTxn.Status = roachpb.COMMITTED

	// Notify the lock table about the committed transaction
	m.OnTransactionUpdated(ctx, committedTxn)

	// Finish the request
	m.FinishReq(ctx, g)

	// At this point, the intent should be resolved in the lock table
	// Further requests on the same key should not be blocked by this transaction
}

// TestIntentResolutionAfterAbort verifies that intents are properly released
// when a transaction aborts.
func TestIntentResolutionAfterAbort(t *testing.T) {
	defer leaktest.AfterTest(t)()
	defer log.Scope(t).Close(t)

	ctx := context.Background()
	c := newCluster()
	c.enableTxnPushes()
	m := concurrency.NewManager(c.makeConfig())
	m.OnRangeLeaseUpdated(1, true /* isLeaseholder */)
	defer m.Close()

	txnID := uuid.MakeV4()
	txn := &roachpb.Transaction{
		TxnMeta: enginepb.TxnMeta{
			ID:             txnID,
			IsoLevel:       isolation.Serializable(),
			Epoch:          0,
			WriteTimestamp: hlc.Timestamp{WallTime: 100},
			MinTimestamp:   hlc.Timestamp{WallTime: 100},
			Priority:       roachpb.NormalUserPriority,
		},
		ReadTimestamp:          hlc.Timestamp{WallTime: 100},
		GlobalUncertaintyLimit: hlc.Timestamp{WallTime: 100},
	}

	// Create a write request
	req := concurrency.Request{
		Timestamp: txn.ReadTimestamp,
		Priority:  roachpb.NormalUserPriority,
		Txn:       txn,
		Spans: concurrency.SpanSet{
			Spans: []concurrency.Span{
				{Key: roachpb.Key("abort_key"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("abort_key"), EndKey: roachpb.Key("abort_key_end")},
		},
	}

	g, _, err := m.SequenceReq(ctx, nil, req, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g)

	// Simulate transaction abort
	abortedTxn := txn.Clone()
	abortedTxn.Status = roachpb.ABORTED

	// Notify the lock table about the aborted transaction
	m.OnTransactionUpdated(ctx, abortedTxn)

	// Finish the request
	m.FinishReq(ctx, g)

	// After abort, other transactions should be able to acquire locks on the same key
}

