				{Key: roachpb.Key("deadlock_a"), EndKey: nil},
			},
			BoundarySpan: concurrency.Span{Key: roachpb.Key("deadlock_a"), EndKey: roachpb.Key("deadlock_a_end")},
		},
	}

	g1, _, err := m.SequenceReq(ctx, nil, req1, concurrency.PessimisticEval)
	require.NoError(t, err)
	require.NotNil(t, g1)
	defer m.FinishReq(ctx, g1)

